    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def isValid(index, head):
    cur = head
    while index > 0 and cur:
        cur = cur.next
        index -= 1
    return cur


if __name__ == '__main__':
    head = ListNode(1, ListNode(2, ListNode(3, ListNode(4, ListNode(5)))))
    index = 2
    result = isValid(index, head)
    if result:
        print(result.val)
